async function main() {
  console.log(`Total products to update: ${updates.length}`);

  let successCount = 0;
  let failCount = 0;

  for (const update of updates) {
    try {
      const wordCount = update.description.trim().split(/\s+/).length;
      const metaLen = update.metaDescription.length;

      if (wordCount < 250) {
        console.log(`⚠️  SHORT: ${update.slug} — ${wordCount} words`);
      }
      if (metaLen < 130 || metaLen > 155) {
        console.log(`⚠️  META: ${update.slug} — ${metaLen} chars (need 130-155)`);
      }

      const result = await prisma.product.update({
        where: { slug: update.slug },
        data: {
          description: update.description,
          metaDescription: update.metaDescription,
        },
      });

      successCount++;
      console.log(`✅ ${update.slug} — ${wordCount} words, meta ${metaLen} chars`);
    } catch (err) {
      failCount++;
      console.error(`❌ FAILED: ${update.slug} — ${err.message}`);
    }
  }

  console.log(`\n=== DONE ===`);
  console.log(`Success: ${successCount}`);
  console.log(`Failed: ${failCount}`);
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
